        switch variant {

        case 1: return .initialized

        case 2: return .hotkeyGenerated

        case 3: return .delegationConstructed

        case 4: return .delegationProved

        case 5: return .voteReady

        default: throw UniffiInternalError.unexpectedEnumCase
