        case .hotkeyGenerated:
            writeInt(&buf, Int32(2))


        case .delegationConstructed:
            writeInt(&buf, Int32(3))


        case .delegationProved:
            writeInt(&buf, Int32(4))


        case .voteReady:
            writeInt(&buf, Int32(5))

        }
    }
}


